'use client';

import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { RoleGate } from '@/components/shared/role-gate';
import { MOCK_CAMPAIGNS } from '@/lib/mock/data';
import { CAMPAIGN_STATUS_CONFIG, CAMPAIGN_TYPE_CONFIG } from '@/lib/constants/campaigns';
import { useOrgStore } from '@/stores/org-store';

export default function CampaignsPage() {
  const getTeam = useOrgStore((s) => s.getTeam);

  return (
    <div>
      <div className="mb-6 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-black tracking-tight text-black">Campaigns</h1>
          <p className="text-sm text-neutral-500">
            {MOCK_CAMPAIGNS.length} campaigns across all teams
          </p>
        </div>
        <RoleGate permission="campaign:create">
          <Button size="sm">+ New Campaign</Button>
        </RoleGate>
      </div>

      <div className="space-y-3">
        {MOCK_CAMPAIGNS.map((campaign) => {
          const team = campaign.team_id ? getTeam(campaign.team_id) : null;
          const statusConfig = CAMPAIGN_STATUS_CONFIG[campaign.status];
          const typeConfig = CAMPAIGN_TYPE_CONFIG[campaign.campaign_type];

          return (
            <Card key={campaign.id} padding="md" shadow={false} className="hover:shadow-[3px_3px_0px_0px_#000] transition-shadow cursor-pointer">
              <div className="flex items-center justify-between">
                <div className="min-w-0 flex-1">
                  <div className="mb-1 flex items-center gap-2">
                    <h3 className="text-sm font-black text-black">{campaign.name}</h3>
                    <Badge variant="outline">{statusConfig.label}</Badge>
                    <Badge color="neutral">{typeConfig.label}</Badge>
                  </div>
                  <p className="truncate text-xs text-neutral-500">
                    {campaign.description}
                  </p>
                  <div className="mt-2 flex items-center gap-3 text-xs text-neutral-400">
                    {team && <span>{team.name}</span>}
                    {campaign.planned_start_date && (
                      <span>
                        {new Date(campaign.planned_start_date).toLocaleDateString('en-IN', { month: 'short', day: 'numeric' })}
                        {campaign.planned_end_date && ` — ${new Date(campaign.planned_end_date).toLocaleDateString('en-IN', { month: 'short', day: 'numeric' })}`}
                      </span>
                    )}
                    {campaign.tags.length > 0 && (
                      <span>{campaign.tags.join(', ')}</span>
                    )}
                  </div>
                </div>
              </div>
            </Card>
          );
        })}
      </div>
    </div>
  );
}
