'use client';

import type { ReactNode } from 'react';
import type { OrgRole } from '@/types';
import type { Permission } from '@/lib/constants/roles';
import { useAuthStore } from '@/stores/auth-store';
import { hasPermission, hasMinRole } from '@/lib/constants/roles';

interface RoleGateProps {
  children: ReactNode;
  /** Show children only if user has this specific permission */
  permission?: Permission;
  /** Show children only if user's role is >= this role */
  minRole?: OrgRole;
  /** What to show when access is denied (defaults to nothing) */
  fallback?: ReactNode;
}

export const RoleGate = ({
  children,
  permission,
  minRole,
  fallback = null,
}: RoleGateProps) => {
  const role = useAuthStore((s) => s.role);

  if (permission && !hasPermission(role, permission)) {
    return <>{fallback}</>;
  }

  if (minRole && !hasMinRole(role, minRole)) {
    return <>{fallback}</>;
  }

  return <>{children}</>;
};
